#include <stdlib.h>
#include <string.h>
#include <ctype.h>

static char api_key[256] = {0};
static int key_loaded = 0;

static void load_api_key(void) {
    if (key_loaded) return;
    FILE *f = fopen("/app/config/api.key", "r");
    if (!f) {
        key_loaded = 1;
        return;
    }
    if (fgets(api_key, sizeof(api_key), f)) {
        /* trim whitespace from both ends */
        char *start = api_key;
        while (*start && isspace((unsigned char)*start)) start++;
        char *end = start + strlen(start) - 1;
        while (end >= start && isspace((unsigned char)*end)) *end-- = '\0';
        if (start != api_key) memmove(api_key, start, strlen(start) + 1);
    }
    fclose(f);
    key_loaded = 1;
}

int api_key_valid(struct MHD_Connection *connection) {
    load_api_key();
    const char *provided = MHD_lookup_connection_value(connection, MHD_HEADER_KIND, "X-API-Key");
    if (!provided || strlen(api_key) == 0) return 0;
    return strcmp(provided, api_key) == 0 ? 1 : 0;
}
