    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *pos = strstr(json, search);
    if (!pos) return NULL;
    pos += strlen(search);
    /* skip whitespace and colon */
    while (*pos && (isspace((unsigned char)*pos) || *pos == ':')) pos++;
    if (*pos == 'n' && strncmp(pos, "null", 4) == 0) return NULL;
    if (*pos != '"') return NULL;
    pos++; /* skip opening quote */
    /* find end of string, handling escapes */
    size_t cap = 1024;
    char *result = malloc(cap);
    size_t len = 0;
    while (*pos && *pos != '"') {
        if (len + 8 >= cap) {
            cap *= 2;
            result = realloc(result, cap);
        }
        if (*pos == '\\') {
            pos++;
            switch (*pos) {
                case '"': result[len++] = '"'; break;
                case '\\': result[len++] = '\\'; break;
                case '/': result[len++] = '/'; break;
                case 'n': result[len++] = '\n'; break;
                case 'r': result[len++] = '\r'; break;
                case 't': result[len++] = '\t'; break;
                case 'b': result[len++] = '\b'; break;
                case 'f': result[len++] = '\f'; break;
                case 'u': {
                    /* basic unicode escape - just copy as-is for ASCII range */
                    if (pos[1] && pos[2] && pos[3] && pos[4]) {
                        char hex[5] = {pos[1], pos[2], pos[3], pos[4], 0};
                        unsigned int codepoint = (unsigned int)strtoul(hex, NULL, 16);
                        if (codepoint < 0x80) {
                            result[len++] = (char)codepoint;
                        } else if (codepoint < 0x800) {
                            result[len++] = (char)(0xC0 | (codepoint >> 6));
                            result[len++] = (char)(0x80 | (codepoint & 0x3F));
                        } else {
                            result[len++] = (char)(0xE0 | (codepoint >> 12));
                            result[len++] = (char)(0x80 | ((codepoint >> 6) & 0x3F));
                            result[len++] = (char)(0x80 | (codepoint & 0x3F));
                        }
                        pos += 4;
                    }
                    break;
                }
                default: result[len++] = *pos; break;
            }
        } else {
            result[len++] = *pos;
        }
        pos++;
    }
    result[len] = '\0';
    return result;
}

/* Check if a key exists in JSON (even if value is empty string) */
static int json_has_key(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    return strstr(json, search) != NULL;
}

static int parse_id_from_url(const char *url) {
    /* url is /api/notes/{id} */
    const char *p = url + strlen("/api/notes/");
    if (*p == '\0' || *p == '?') return -1;
    /* check all digits */
    const char *check = p;
    while (*check) {
        if (!isdigit((unsigned char)*check)) return -1;
        check++;
    }
    return atoi(p);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return send_json(connection, "", 200);
    }

    /* For POST/PUT, we need to accumulate the body across multiple calls */
    if (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            ci->data = NULL;
            ci->data_size = 0;
            *con_cls = ci;
            return MHD_YES;
        }

        struct connection_info *ci = *con_cls;

        if (*upload_data_size > 0) {
            /* Check body size limit */
            if (ci->data_size + *upload_data_size > MAX_BODY_SIZE) {
                *upload_data_size = 0;
                ci->data_size = MAX_BODY_SIZE + 1; /* mark as too large */
                return MHD_YES;
            }
            ci->data = realloc(ci->data, ci->data_size + *upload_data_size + 1);
            memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
            ci->data_size += *upload_data_size;
            ci->data[ci->data_size] = '\0';
            *upload_data_size = 0;
            return MHD_YES;
        }

        /* All data received - process the request */
        if (ci->data_size > MAX_BODY_SIZE) {
            return send_json(connection, "{\"error\":\"payload too large\"}", 413);
        }

        const char *body = ci->data ? ci->data : "";

        if (strcmp(method, "POST") == 0 && strcmp(url, "/api/notes") == 0) {
            /* Auth check */
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", 401);
            }

            /* Parse title and content */
            char *title = json_get_string(body, "title");
            char *content = json_get_string(body, "content");

            /* Validate title */
            if (!title || strlen(title) == 0) {
                if (title) free(title);
                if (content) free(content);
                return send_json(connection, "{\"error\":\"title is required\"}", 400);
            }

            int id = create_note(title, content ? content : "");
            if (id < 0) {
                free(title);
                if (content) free(content);
                return send_json(connection, "{\"error\":\"database error\"}", 500);
            }

            /* Build response */
            char *note_json = get_note_json(id);
            enum MHD_Result r;
            if (note_json) {
                r = send_json(connection, note_json, 201);
                free(note_json);
            } else {
                /* fallback - shouldn't happen */
                char resp[65536];
                char *etitle = malloc(strlen(title) * 6 + 1);
                char *econtent = malloc((content ? strlen(content) : 0) * 6 + 1);
                /* simple fallback */
                snprintf(resp, sizeof(resp), "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\"}",
                         id, title, content ? content : "");
                free(etitle);
                free(econtent);
                r = send_json(connection, resp, 201);
            }
            free(title);
            if (content) free(content);
            return r;
        }

        if (strcmp(method, "PUT") == 0 && strncmp(url, "/api/notes/", 11) == 0) {
            /* Auth check */
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", 401);
            }

            int id = parse_id_from_url(url);
            if (id < 0) {
                return send_json(connection, "{\"error\":\"not found\"}", 404);
            }

            /* Parse title and content */
            char *title = json_get_string(body, "title");
            char *content = json_get_string(body, "content");

            /* Validate title - same rules as POST */
            if (!title || strlen(title) == 0) {
                if (title) free(title);
                if (content) free(content);
                return send_json(connection, "{\"error\":\"title is required\"}", 400);
            }

            int result = update_note(id, title, content ? content : "");
            free(title);
            if (content) free(content);

            if (result == 1) {
                return send_json(connection, "{\"error\":\"not found\"}", 404);
            } else if (result < 0) {
                return send_json(connection, "{\"error\":\"database error\"}", 500);
            }

            char *note_json = get_note_json(id);
            if (note_json) {
                enum MHD_Result r = send_json(connection, note_json, 200);
                free(note_json);
                return r;
            }
            return send_json(connection, "{\"error\":\"not found\"}", 404);
        }

        /* POST/PUT to unknown URL */
        return send_json(connection, "{\"error\":\"not found\"}", 404);
    }

    /* DELETE needs body accumulation handling too (though typically no body) */
    if (strcmp(method, "DELETE") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            *con_cls = ci;
            return MHD_YES;
        }
        if (*upload_data_size > 0) {
            *upload_data_size = 0;
            return MHD_YES;
        }

        if (strncmp(url, "/api/notes/", 11) != 0) {
            return send_json(connection, "{\"error\":\"not found\"}", 404);
        }

        /* Auth check */
        if (!api_key_valid(connection)) {
            return send_json(connection, "{\"error\":\"unauthorized\"}", 401);
        }

        int id = parse_id_from_url(url);
        if (id < 0) {
            return send_json(connection, "{\"error\":\"not found\"}", 404);
        }

        int result = delete_note(id);
        if (result == 1) {
            return send_json(connection, "{\"error\":\"not found\"}", 404);
        } else if (result < 0) {
            return send_json(connection, "{\"error\":\"database error\"}", 500);
        }
        return send_json(connection, "{\"status\":\"deleted\"}", 200);
    }

    /* GET requests */
    if (strcmp(method, "GET") == 0) {
        /* GET /api/notes */
        if (strcmp(url, "/api/notes") == 0) {
            const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
            const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");

            int limit = 50;
            int offset = 0;
            if (limit_str) limit = atoi(limit_str);
            if (offset_str) offset = atoi(offset_str);
            if (limit <= 0) limit = 50;
            if (limit > 100) limit = 100;
            if (offset < 0) offset = 0;

            int total = get_total_notes_count();
            char *json = get_notes_paginated_json(limit, offset);
            if (!json) {
                return send_json_with_total(connection, "[]", 200, total);
            }
            enum MHD_Result r = send_json_with_total(connection, json, 200, total);
            free(json);
            return r;
        }

        /* GET /api/notes/{id} */
        if (strncmp(url, "/api/notes/", 11) == 0) {
            int id = parse_id_from_url(url);
            if (id < 0) {
                return send_json(connection, "{\"error\":\"not found\"}", 404);
            }
            char *json = get_note_json(id);
            if (!json) {
                return send_json(connection, "{\"error\":\"not found\"}", 404);
            }
            enum MHD_Result r = send_json(connection, json, 200);
            free(json);
            return r;
        }

        return send_json(connection, "{\"error\":\"not found\"}", 404);
    }

    return send_json(connection, "{\"error\":\"not found\"}", 404);
}
